@Repository
class ProductSearchRepository {

    private final RestHighLevelClient client;
    private final ElasticsearchSearchApplication.ElasticsearchProperties properties;

    ProductSearchRepository(RestHighLevelClient client,
                            ElasticsearchSearchApplication.ElasticsearchProperties properties) {
        this.client = client;
        this.properties = properties;
    }

    public void indexProduct(Product product) throws IOException {
        IndexRequest request = new IndexRequest(properties.getProductIndex())
                .id(product.getId())
                .source(productToMap(product));
        client.index(request, RequestOptions.DEFAULT);
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        for (Product product : products) {
            bulkRequest.add(new IndexRequest(properties.getProductIndex())
                    .id(product.getId())
                    .source(productToMap(product)));
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new IOException("Bulk indexing failed: " + response.buildFailureMessage());
        }
    }

    public ProductSearchResponse search(ProductSearchRequest request) throws IOException {
        MultiSearchRequest multiSearchRequest = new MultiSearchRequest();

        SearchRequest hitsRequest = new SearchRequest(properties.getProductIndex());
        SearchSourceBuilder hitsSource = new SearchSourceBuilder()
                .query(buildSearchQuery(request))
                .from(request.getPage() * request.getSize())
                .size(request.getSize());

        if ("_score".equalsIgnoreCase(request.getSortBy())) {
            hitsSource.sort("_score", resolveSortOrder(request.getSortOrder()));
        } else {
            hitsSource.sort(request.getSortBy(), resolveSortOrder(request.getSortOrder()));
        }

        HighlightBuilder highlightBuilder = new HighlightBuilder()
                .preTags("<em>")
                .postTags("</em>")
                .field("name")
                .field("description");
        hitsSource.highlighter(highlightBuilder);
        hitsRequest.source(hitsSource);

        SearchRequest facetRequest = new SearchRequest(properties.getProductIndex());
        SearchSourceBuilder facetSource = new SearchSourceBuilder()
                .query(buildSearchQuery(request))
                .size(0)
                .aggregation(AggregationBuilders.terms("categories").field("category.keyword").size(20))
                .aggregation(AggregationBuilders.terms("brands").field("brand.keyword").size(20))
                .aggregation(AggregationBuilders.terms("tags").field("tags.keyword").size(30))
                .aggregation(
                        AggregationBuilders.range("price_ranges")
                                .field("price")
                                .addUnboundedTo("under_50", 50)
                                .addRange("50_to_100", 50, 100)
                                .addRange("100_to_500", 100, 500)
                                .addUnboundedFrom("above_500", 500)
                );
        facetRequest.source(facetSource);

        multiSearchRequest.add(hitsRequest);
        multiSearchRequest.add(facetRequest);

        MultiSearchResponse multiSearchResponse = client.msearch(multiSearchRequest, RequestOptions.DEFAULT);

        SearchResponse hitsResponse = multiSearchResponse.getResponses()[0].getResponse();
        SearchResponse facetsResponse = multiSearchResponse.getResponses()[1].getResponse();

        ProductSearchResponse response = new ProductSearchResponse();
        response.setPage(request.getPage());
        response.setSize(request.getSize());
        response.setTotal(hitsResponse.getHits().getTotalHits().value);
        response.setProducts(Arrays.stream(hitsResponse.getHits().getHits()).map(hit -> {
            ProductDocument doc = mapHitToProduct(hit.getSourceAsMap());
            doc.setId(hit.getId());
            if (hit.getHighlightFields() != null) {
                Map<String, List<String>> highlights = new HashMap<>();
                hit.getHighlightFields().forEach((k, v) -> highlights.put(
                        k,
                        Arrays.stream(v.fragments()).map(Object::toString).collect(Collectors.toList())
                ));
                doc.setHighlights(highlights);
            }
            return doc;
        }).collect(Collectors.toList()));
        response.setFacets(mapFacets(facetsResponse));
        return response;
    }

    public void indexSearchQuery(SearchQueryLog log) throws IOException {
        IndexRequest request = new IndexRequest(properties.getQueryLogIndex())
                .id(log.getId() != null ? log.getId() : UUID.randomUUID().toString())
                .source(searchQueryToMap(log));
        client.index(request, RequestOptions.DEFAULT);
    }

    private QueryBuilder buildSearchQuery(ProductSearchRequest request) {
        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            MultiMatchQueryBuilder textQuery = QueryBuilders.multiMatchQuery(request.getQuery(),
                            "name^4", "description^2", "category", "brand", "tags")
                    .operator(Operator.AND)
                    .fuzziness(Fuzziness.AUTO);
            bool.must(textQuery);
        } else {
            bool.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            bool.filter(QueryBuilders.termQuery("category.keyword", request.getCategory()));
        }
        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            bool.filter(QueryBuilders.termQuery("brand.keyword", request.getBrand()));
        }
        if (request.getInStock() != null) {
            bool.filter(QueryBuilders.termQuery("inStock", request.getInStock()));
        }
        if (request.getTags() != null && !request.getTags().isEmpty()) {
            bool.filter(QueryBuilders.termsQuery("tags.keyword", request.getTags()));
        }
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                range.gte(request.getMinPrice().doubleValue());
            }
            if (request.getMaxPrice() != null) {
                range.lte(request.getMaxPrice().doubleValue());
            }
            bool.filter(range);
        }

        return bool;
    }

    private SortOrder resolveSortOrder(String sortOrder) {
        return "asc".equalsIgnoreCase(sortOrder) ? SortOrder.ASC : SortOrder.DESC;
    }

    private ProductDocument mapHitToProduct(Map<String, Object> source) {
        ProductDocument doc = new ProductDocument();
        doc.setSku(asString(source.get("sku")));
        doc.setName(asString(source.get("name")));
        doc.setDescription(asString(source.get("description")));
        doc.setCategory(asString(source.get("category")));
        doc.setTags(asStringList(source.get("tags")));
        doc.setPrice(asDouble(source.get("price")));
        doc.setBrand(asString(source.get("brand")));
        doc.setInStock(asBoolean(source.get("inStock")));
        doc.setQuantity(asInteger(source.get("quantity")));
        doc.setRating(asDouble(source.get("rating")));
        doc.setAttributes(asStringMap(source.get("attributes")));
        doc.setCreatedAt(asString(source.get("createdAt")));
        return doc;
    }

    private FacetResponse mapFacets(SearchResponse response) {
        FacetResponse facets = new FacetResponse();

        ParsedStringTerms categories = response.getAggregations().get("categories");
        if (categories != null) {
            facets.setCategories(categories.getBuckets().stream()
                    .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                    .collect(Collectors.toList()));
        }

        ParsedStringTerms brands = response.getAggregations().get("brands");
        if (brands != null) {
            facets.setBrands(brands.getBuckets().stream()
                    .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                    .collect(Collectors.toList()));
        }

        ParsedStringTerms tags = response.getAggregations().get("tags");
        if (tags != null) {
            facets.setTags(tags.getBuckets().stream()
                    .map(b -> new FacetBucket(b.getKeyAsString(), b.getDocCount()))
                    .collect(Collectors.toList()));
        }

        ParsedRange priceRanges = response.getAggregations().get("price_ranges");
        if (priceRanges != null) {
            facets.setPriceRanges(priceRanges.getBuckets().stream()
                    .map(b -> new PriceRangeBucket(
                            b.getKeyAsString(),
                            b.getFromAsString(),
                            b.getToAsString(),
                            b.getDocCount()))
                    .collect(Collectors.toList()));
        }

        return facets;
    }

    private Map<String, Object> productToMap(Product product) {
        Map<String, Object> source = new HashMap<>();
        source.put("sku", product.getSku());
        source.put("name", product.getName());
        source.put("description", product.getDescription());
        source.put("category", product.getCategory());
        source.put("tags", product.getTags());
        source.put("price", product.getPrice() != null ? product.getPrice().doubleValue() : null);
        source.put("brand", product.getBrand());
        source.put("inStock", product.isInStock());
        source.put("quantity", product.getQuantity());
        source.put("rating", product.getRating());
        source.put("attributes", product.getAttributes());
        source.put("createdAt", product.getCreatedAt() != null ? product.getCreatedAt().toString() : Instant.now().toString());
        return source;
    }

    private Map<String, Object> searchQueryToMap(SearchQueryLog log) {
        Map<String, Object> source = new HashMap<>();
        source.put("query", log.getQuery());
        source.put("filters", log.getFilters());
        source.put("resultsCount", log.getResultsCount());
        source.put("sessionId", log.getSessionId());
        source.put("customerId", log.getCustomerId());
        source.put("searchedAt", log.getSearchedAt() != null ? log.getSearchedAt().toString() : Instant.now().toString());
        return source;
    }

    private String asString(Object o) {
        return o == null ? null : String.valueOf(o);
    }

    private Double asDouble(Object o) {
        if (o == null) return null;
        if (o instanceof Number) return ((Number) o).doubleValue();
        return Double.valueOf(String.valueOf(o));
    }

    private Integer asInteger(Object o) {
        if (o == null) return null;
        if (o instanceof Number) return ((Number) o).intValue();
        return Integer.valueOf(String.valueOf(o));
    }

    private Boolean asBoolean(Object o) {
        if (o == null) return null;
        if (o instanceof Boolean) return (Boolean) o;
        return Boolean.valueOf(String.valueOf(o));
    }

    @SuppressWarnings("unchecked")
    private List<String> asStringList(Object o) {
        if (o == null) return new ArrayList<>();
        return ((List<Object>) o).stream().map(String::valueOf).collect(Collectors.toList());
    }

    @SuppressWarnings("unchecked")
    private Map<String, String> asStringMap(Object o) {
        if (o == null) return new HashMap<>();
        Map<String, Object> input = (Map<String, Object>) o;
        return input.entrySet().stream().collect(Collectors.toMap(Map.Entry::getKey, e -> String.valueOf(e.getValue())));
    }
}

@Service
class IndexManagementService {

    private final RestHighLevelClient client;
    private final ElasticsearchSearchApplication.ElasticsearchProperties properties;

    IndexManagementService(RestHighLevelClient client,
                           ElasticsearchSearchApplication.ElasticsearchProperties properties) {
        this.client = client;
        this.properties = properties;
    }

    public void initialize() throws IOException {
        createProductIndexIfMissing();
        createQueryLogIndexIfMissing();
    }

    public void recreateAll() throws IOException {
        deleteIndexIfExists(properties.getProductIndex());
        deleteIndexIfExists(properties.getQueryLogIndex());
        initialize();
    }

    private void createProductIndexIfMissing() throws IOException {
        if (!client.indices().exists(new GetIndexRequest(properties.getProductIndex()), RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(properties.getProductIndex());
            request.source("{\n" +
                    "  \"settings\": {\n" +
                    "    \"analysis\": {\n" +
                    "      \"normalizer\": {\n" +
                    "        \"lowercase_normalizer\": {\n" +
                    "          \"type\": \"custom\",\n" +
                    "          \"filter\": [\"lowercase\"]\n" +
                    "        }\n" +
                    "      }\n" +
                    "    }\n" +
                    "  },\n" +
                    "  \"mappings\": {\n" +
                    "    \"properties\": {\n" +
                    "      \"sku\": {\"type\": \"keyword\"},\n" +
                    "      \"name\": {\n" +
                    "        \"type\": \"text\",\n" +
                    "        \"fields\": {\n" +
                    "          \"keyword\": {\"type\": \"keyword\", \"ignore_above\": 256}\n" +
                    "        }\n" +
                    "      },\n" +
                    "      \"description\": {\"type\": \"text\"},\n" +
                    "      \"category\": {\n" +
                    "        \"type\": \"text\",\n" +
                    "        \"fields\": {\n" +
                    "          \"keyword\": {\"type\": \"keyword\", \"normalizer\": \"lowercase_normalizer\"}\n" +
                    "        }\n" +
                    "      },\n" +
                    "      \"tags\": {\n" +
                    "        \"type\": \"text\",\n" +
                    "        \"fields\": {\n" +
                    "          \"keyword\": {\"type\": \"keyword\", \"normalizer\": \"lowercase_normalizer\"}\n" +
                    "        }\n" +
                    "      },\n" +
                    "      \"price\": {\"type\": \"double\"},\n" +
                    "      \"brand\": {\n" +
                    "        \"type\": \"text\",\n" +
                    "        \"fields\": {\n" +
                    "          \"keyword\": {\"type\": \"keyword\", \"normalizer\": \"lowercase_normalizer\"}\n" +
                    "        }\n" +
                    "      },\n" +
                    "      \"inStock\": {\"type\": \"boolean\"},\n" +
                    "      \"quantity\": {\"type\": \"integer\"},\n" +
                    "      \"rating\": {\"type\": \"double\"},\n" +
                    "      \"attributes\": {\"type\": \"object\", \"dynamic\": true},\n" +
                    "      \"createdAt\": {\"type\": \"date\"}\n" +
                    "    }\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }
    }

    private void createQueryLogIndexIfMissing() throws IOException {
        if (!client.indices().exists(new GetIndexRequest(properties.getQueryLogIndex()), RequestOptions.DEFAULT)) {
            CreateIndexRequest request = new CreateIndexRequest(properties.getQueryLogIndex());
            request.source("{\n" +
                    "  \"mappings\": {\n" +
                    "    \"properties\": {\n" +
                    "      \"query\": {\"type\": \"text\"},\n" +
                    "      \"filters\": {\"type\": \"object\", \"dynamic\": true},\n" +
                    "      \"resultsCount\": {\"type\": \"integer\"},\n" +
                    "      \"sessionId\": {\"type\": \"keyword\"},\n" +
                    "      \"customerId\": {\"type\": \"keyword\"},\n" +
                    "      \"searchedAt\": {\"type\": \"date\"}\n" +
                    "    }\n" +
                    "  }\n" +
                    "}", XContentType.JSON);
            client.indices().create(request, RequestOptions.DEFAULT);
        }
    }

    private void deleteIndexIfExists(String index) throws IOException {
        if (client.indices().exists(new GetIndexRequest(index), RequestOptions.DEFAULT)) {
            client.indices().delete(new DeleteIndexRequest(index), RequestOptions.DEFAULT);
        }
    }
}

@Service
class ProductSearchService {

    private final ProductSearchRepository repository;

    ProductSearchService(ProductSearchRepository repository) {
        this.repository = repository;
    }

    public void indexProduct(Product product) throws IOException {
        repository.indexProduct(product);
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        repository.bulkIndexProducts(products);
    }

    public ProductSearchResponse search(ProductSearchRequest request) throws IOException {
        ProductSearchResponse response = repository.search(request);
        SearchQueryLog log = new SearchQueryLog();
        log.setId(UUID.randomUUID().toString());
        log.setQuery(request.getQuery() != null ? request.getQuery() : "");
        log.setFilters(extractFilters(request));
        log.setResultsCount((int) response.getTotal());
        log.setSessionId(request.getSessionId());
        log.setCustomerId(request.getCustomerId());
        log.setSearchedAt(Instant.now());
        repository.indexSearchQuery(log);
        return response;
    }

    private Map<String, Object> extractFilters(ProductSearchRequest request) {
        Map<String, Object> filters = new HashMap<>();
        if (request.getCategory() != null) filters.put("category", request.getCategory());
        if (request.getBrand() != null) filters.put("brand", request.getBrand());
        if (request.getInStock() != null) filters.put("inStock", request.getInStock());
        if (request.getTags() != null && !request.getTags().isEmpty()) filters.put("tags", request.getTags());
        if (request.getMinPrice() != null) filters.put("minPrice", request.getMinPrice());
        if (request.getMaxPrice() != null) filters.put("maxPrice", request.getMaxPrice());
        return filters;
    }
}

@RestController
@RequestMapping("/api/products")
class ProductController {

    private final ProductSearchService productSearchService;

    ProductController(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @PostMapping("/index")
    public ResponseEntity<Map<String, Object>> indexProduct(@Valid @RequestBody Product product) throws IOException {
        productSearchService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("message", "Product indexed successfully", "productId", product.getId()));
    }

    @PostMapping("/index/bulk")
    public ResponseEntity<Map<String, Object>> bulkIndexProducts(@Valid @RequestBody List<Product> products) throws IOException {
        productSearchService.bulkIndexProducts(products);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("message", "Products indexed successfully", "count", products.size()));
    }

    @PostMapping("/search")
    public ResponseEntity<ProductSearchResponse> search(@RequestBody ProductSearchRequest request) throws IOException {
        return ResponseEntity.ok(productSearchService.search(request));
    }
}

@RestController
@RequestMapping("/api/admin/search")
class SearchAdminController {

    private final IndexManagementService indexManagementService;

    SearchAdminController(IndexManagementService indexManagementService) {
        this.indexManagementService = indexManagementService;
    }

    @PostMapping("/indices/recreate")
    public ResponseEntity<Map<String, String>> recreateIndices() throws IOException {
        indexManagementService.recreateAll();
        return ResponseEntity.ok(Map.of("message", "Elasticsearch indices recreated successfully"));
    }
}